-- proxquery — structured match corpus (single source of truth, part 2)
-- =====================================================================
-- The `(doc, query) -> expected` recheck cases, as typed tuples rather than the
-- opaque exprs in proxquery_cases.sql. Keeping doc and query split lets the SAME
-- data drive three things:
--   * the portable function check `ts_prox_match(to_tsvector('simple',doc), query)`
--     on BOTH implementations (proxquery_diff_test.sql / proxquery_pure_test.sql),
--   * the extension-only operator/index test, which builds one indexed temp table
--     from the distinct docs and runs `tsv @~@ query` (proxquery_operator_test.sql).
-- `expected` is the `::text` of the recheck (true/false). Error and literal-
-- tsvector cases stay in proxquery_cases.sql (they aren't `to_tsvector(doc)` pairs).
-- doc/query are dollar-quoted so quotes, backslashes and `|` need no escaping.

DROP TABLE IF EXISTS _prox_match;
CREATE TEMP TABLE _prox_match(label text, doc text, query text, expected text);

  -- non-ASCII: accented Latin and CJK. Locale-INDEPENDENT (no uppercase to case-fold),
  -- so they agree on any CI collation. Two things are deliberately NOT asserted here
  -- because their tokenization is locale-dependent (see docs/CONFIG_AWARE.md):
  -- uppercase-accent case-folding, and emoji (a token under C, dropped under en_US.UTF-8).
  ('u1',  $d$le café est bon$d$,                     $q$café$q$,                                $x$true$x$),
  ('u2',  $d$le café est bon$d$,                     $q$café <~2> bon$q$,                       $x$true$x$),
  ('u3',  $d$le café est bon$d$,                     $q$café <~1> bon$q$,                       $x$false$x$),
  ('u4',  $d$résumé and resume$d$,                   $q$résumé$q$,                              $x$true$x$),
  ('u5',  $d$plain resume here$d$,                   $q$résumé$q$,                              $x$false$x$),
  ('u6',  $d$el niño pequeño$d$,                     $q$niño$q$,                                $x$true$x$),
  ('u7',  $d$el niño pequeño$d$,                     $q$nino$q$,                                $x$false$x$),
  ('u8',  $d$中文 文档 搜索$d$,                        $q$中文$q$,                                 $x$true$x$),
  ('u9',  $d$中文 文档 搜索$d$,                        $q$中文 <~2> 搜索$q$,                       $x$true$x$),
  ('u10', $d$中文 文档 搜索$d$,                        $q$中文 <~1> 搜索$q$,                       $x$false$x$),
  ('u11', $d$日本語$d$,                               $q$日本$q$,                                 $x$false$x$);
